from collections import defaultdict
from typing import Dict, List, Tuple

def build_vocab(corpus: str) -> Dict[Tuple[str, ...], int]:
    """Split corpus into word-frequency pairs with end-of-word markers."""
    vocab: Dict[Tuple[str, ...], int] = defaultdict(int)
    for word in corpus.strip().split():
        chars = tuple(list(word) + ["</w>"])
        vocab[chars] += 1
    return dict(vocab)

def count_pairs(vocab: Dict[Tuple[str, ...], int]) -> Dict[Tuple[str, str], int]:
    """Count frequency of every adjacent symbol pair weighted by word frequency."""
    pairs: Dict[Tuple[str, str], int] = defaultdict(int)
    for symbols, freq in vocab.items():
        for i in range(len(symbols) - 1):
            pairs[(symbols[i], symbols[i + 1])] += freq
    return dict(pairs)

def merge_vocab(pair: Tuple[str, str], vocab: Dict[Tuple[str, ...], int]) -> Dict[Tuple[str, ...], int]:
    """Apply one merge rule (pair -> merged_token) to the vocabulary."""
    new_vocab: Dict[Tuple[str, ...], int] = {}
    a, b = pair
    merged = a + b
    for symbols, freq in vocab.items():
        result = []
        i = 0
        while i < len(symbols):
            if i < len(symbols) - 1 and symbols[i] == a and symbols[i + 1] == b:
                result.append(merged)
                i += 2
            else:
                result.append(symbols[i])
                i += 1
        new_vocab[tuple(result)] = freq
    return new_vocab

def train_bpe(corpus: str, num_merges: int, verbose: bool = False) -> List[Tuple[str, str]]:
    """Train BPE and return the ordered list of merge rules."""
    vocab = build_vocab(corpus)
    merges: List[Tuple[str, str]] = []
    for i in range(num_merges):
        pair_counts = count_pairs(vocab)
        if not pair_counts:
            break
        best = max(pair_counts, key=pair_counts.__getitem__)
        vocab = merge_vocab(best, vocab)
        merges.append(best)
        if verbose:
            print(f"Merge {i+1:3d}: {best[0]!r} + {best[1]!r} -> {(best[0]+best[1])!r}  (count={pair_counts[best]})")
    return merges

corpus = "low low low lower lower newest newest newest newest widest widest"
merges = train_bpe(corpus, num_merges=10, verbose=True)
print(f"\nLearned {len(merges)} merge rules")

def encode_text(text: str, merge_rules: list, vocab: dict) -> list[int]:
    """Apply learned merge rules to encode new text."""
    # Step 1: character-split each word
    word_tokens = []
    for word in text.strip().split():
        word_tokens.append(list(word) + ["</w>"])

    # Step 2: apply each merge rule in training order
    for rule_a, rule_b in merge_rules:
        merged = rule_a + rule_b
        new_word_tokens = []
        for chars in word_tokens:
            result = []
            i = 0
            while i < len(chars):
                if i < len(chars) - 1 and chars[i] == rule_a and chars[i + 1] == rule_b:
                    result.append(merged)
                    i += 2
                else:
                    result.append(chars[i])
                    i += 1
            new_word_tokens.append(result)
        word_tokens = new_word_tokens

    # Step 3: map each token to its integer ID
    ids = []
    for chars in word_tokens:
        for tok in chars:
            ids.append(vocab.get(tok, -1))  # -1 for unknown
    return ids

# After training BPE, encode unseen text
merges = train_bpe("low low lower newest", num_merges=8)
vocab_map = {tok: i for i, tok in enumerate(sorted(set(
    t for merge in merges for t in [merge[0], merge[1], merge[0]+merge[1]]
) | set("low lower</w>")))}

ids = encode_text("low lower", merges, vocab_map)
print("Token IDs:", ids)
